#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX 300005

int sum_of_squares(int n) {
    int sum = 0;
    while (n > 0) {
        int digit = n % 10;
        sum += digit * digit;
        n /= 10;
    }
    return sum;
}

int main() {
    int q, N, M;
    scanf("%d %d", &q, &N);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    scanf("%d", &M);
    int B[N];
    int magic_numbers[MAX] = {0};
    int magic_index = 0;
    for (int i = 1; i < MAX; i++) {
        if (sum_of_squares(i) <= q) {
            magic_numbers[magic_index++] = i;
        }
    }
    for (int i = 0; i < N; i++) {
        B[i] = magic_numbers[A[i] - 1];
    }
    long long prefix_sum[N + 1] = {0};
    for (int i = 0; i < N; i++) {
        prefix_sum[i + 1] = prefix_sum[i] + B[i];
    }
    for (int i = 0; i < M; i++) {
        int l, r;
        scanf("%d %d", &l, &r);
        long long sum = (prefix_sum[r] - prefix_sum[l - 1]) % MOD;
        printf("%lld\n", sum);
    }
    return 0;
}

